     4| * Synchronous JSON loader with optional TTL cache.
     5| * Reads from the filesystem using Node.js require or fs.
     6| */
     7|export function loadJSON<T = any>(filePath: string, cache?: { data: T; timestamp: number; ttlMs: number }): {
     8|  data: T
     9|  cache: typeof cache
    10|} {
    11|  const now = Date.now()
    12|  if (cache && now - cache.timestamp < cache.ttlMs) {
    13|    return { data: cache.data, cache }
    14|  }
    15|
    16|  const fs = require("fs")
    17|  const path = require("path")
    18|
    19|  const locations = [
    20|    filePath,
    21|    path.join(process.cwd(), filePath),
    22|    path.join(process.cwd(), "..", filePath),
    23|    path.join(process.cwd(), "..", "..", filePath),
    24|  ]
    25|
    26|  let raw: string | null = null
    27|  let resolvedPath: string | null = null
    28|
    29|  for (const loc of locations) {
    30|    try {
    31|      raw = fs.readFileSync(loc, "utf-8")
    32|      resolvedPath = loc
    33|      break
    34|    } catch {}
    35|  }
    36|
    37|  if (!raw) {
    38|    throw new Error(`[@ai-whisperers/content] Cannot find file: ${filePath}. Tried: ${locations.join(", ")}`)
    39|  }
    40|
    41|  const data = JSON.parse(raw) as T
    42|  return { data, cache: { data, timestamp: now, ttlMs: cache?.ttlMs || 60000 } }
