    38|  get(key) {
    39|    const entry = this.cache.get(key);
    40|    if (!entry) return null;
    41|    if (Date.now() - entry.timestamp > this.ttlMs) {
    42|      this.cache.delete(key);
    43|      return null;
    44|    }
    45|    // Move to end (most recently used)
    46|    this.cache.delete(key);
    47|    this.cache.set(key, entry);
    48|    return entry.value;
    49|  }
    50|
    51|  set(key, value) {
    52|    if (this.cache.size >= this.maxSize) {
    53|      // Delete oldest (first item)
